// Prepare Files for AI Test Generation (MS1)
// Takes Rule based filter output and creates a prioritised list:
//   1. rejected_missing_tests (0% coverage) — highest priority
//   2. removed_low_coverage (below 85%) — sorted worst first
// Caps at MAX_FILES to control OpenAI cost per run.

const input = $input.first().json;
const MAX_FILES = 3;

const missing = (input.rejected_missing_tests || []).map(f => ({
  file: typeof f === 'string' ? f : f.file,
  avgCoverage: 0,
  priority: 'missing',
  owner: 'cs4218',
  repo: 'cs4218-2520-ecom-project-cs4218-2520-team5',
  branch: 'main',
  testOutputPath: 'tests/integration/' + (typeof f === 'string' ? f : f.file).split('/').pop().replace('.js', '') + '.ai-generated.test.js',
}));

const lowCov = (input.removed_low_coverage || [])
  .map(f => ({
    file: f.file,
    avgCoverage: f.avgCoverage,
    priority: 'low_coverage',
    owner: 'cs4218',
    repo: 'cs4218-2520-ecom-project-cs4218-2520-team5',
    branch: 'main',
    testOutputPath: 'tests/integration/' + f.file.split('/').pop().replace('.js', '') + '.ai-generated.test.js',
  }))
  .sort((a, b) => a.avgCoverage - b.avgCoverage);

const files = [...missing, ...lowCov].slice(0, MAX_FILES);

if (files.length === 0) {
  throw new Error('No files need test generation — all meet the 85% coverage threshold.');
}

return files.map(f => ({ json: f }));

// Build Prompt (MS1) — assembles the GPT-4o prompt from the fetched source file.
// References the loop node to recover file metadata (file path, coverage %, etc.)
// because the Fetch Source File HTTP node replaces $json with the GitHub API response.

const fileData = $input.first().json;
const loopItem = $('Loop Through Files (P3)').item.json;

// Decode the base64-encoded file content from the GitHub Contents API response
let sourceCode;
try {
  sourceCode = Buffer.from(fileData.content, 'base64').toString('utf-8');
} catch (e) {
  throw new Error(`Failed to decode source for ${loopItem.file}: ${e.message}`);
}

const systemPrompt = `You are an expert software engineer writing Jest integration tests for a MERN stack e-commerce application called Virtual Vault.

Stack: Node.js, Express, Mongoose, MongoDB.
Test framework: Jest 29 with Babel (ESM via --experimental-vm-modules).
Integration tests use: MongoMemoryServer, Supertest, real Express routes, real Mongoose models.

Rules:
- Do NOT mock the controller or model layer under test. Only replace external dependencies: MongoDB -> MongoMemoryServer, Braintree -> jest.fn().
- Use ES module syntax (import/export). No require().
- Every test() must have at least one expect() assertion.
- Group tests in describe() blocks by function name.
- Return ONLY the test file code inside a single \`\`\`javascript ... \`\`\` block.`;

const userPrompt = `File to test: ${loopItem.file}
Current coverage: ${loopItem.avgCoverage}% (priority: ${loopItem.priority})

SOURCE CODE:
\`\`\`javascript
${sourceCode}
\`\`\`

Write complete Jest integration tests covering all exported functions. For each controller function write at minimum:
1. Happy path (valid inputs, expect 200/success)
2. Missing required field (expect 400)
3. Not found case where applicable (expect 404)
4. Apply,if applicable, boundary value analysis or equivalence partitioning when writing test cases.

Use this setup pattern:
\`\`\`javascript
import { MongoMemoryServer } from 'mongodb-memory-server';
import mongoose from 'mongoose';
import request from 'supertest';
import jwt from 'jsonwebtoken';
import express from 'express';

let mongoServer, app;
beforeAll(async () => {
  process.env.JWT_SECRET = 'testsecret';
  mongoServer = await MongoMemoryServer.create();
  await mongoose.connect(mongoServer.getUri());
  app = express();
  app.use(express.json());
  app.use('/api/v1/...', routes);
});
afterAll(async () => { await mongoose.disconnect(); await mongoServer.stop(); });
afterEach(async () => { await SomeModel.deleteMany({}); });
\`\`\`

Generate the complete test file now:`;

return [{ json: {
  file: loopItem.file,
  avgCoverage: loopItem.avgCoverage,
  priority: loopItem.priority,
  owner: loopItem.owner,
  repo: loopItem.repo,
  branch: loopItem.branch,
  testOutputPath: loopItem.testOutputPath,
  sourceCode,
  systemPrompt,
  userPrompt,
} }];

// Format Test File — Code Node (MS1)
// Person 3's primary MS1 deliverable.
//
// Steps:
//   1. Extract the ```javascript ... ``` code block from GPT-4o's response
//   2. Enforce author comment at top of file
//   3. Normalise line endings and strip trailing whitespace
//   4. Return structured output with filename, source, line count

const response = $input.first().json;
const buildData = $('Build Prompt (P3)').item.json;

// Step 1: Extract content from OpenAI response (choices[0].message.content)
let rawText = '';
if (response.choices && Array.isArray(response.choices)) {
  rawText = response.choices[0]?.message?.content || '';
} else if (typeof response === 'string') {
  rawText = response;
}

if (!rawText) {
  throw new Error(`GPT-4o returned empty content for ${buildData.file}. Check your OpenAI API key and credit balance.`);
}

// Step 2: Extract code block (accepts ```javascript, ```js, or plain ``` blocks)
const codeBlockRegex = /```(?:javascript|js)?\n([\s\S]*?)```/;
const match = rawText.match(codeBlockRegex);
let testCode = match ? match[1].trim() : rawText.trim();

if (!testCode) {
  throw new Error('Could not extract code block from GPT-4o response.');
}

// Step 3: Enforce author comment at top to distinguish from 
const authorLine = '// Auto-generated by n8n AI Testing Workflow. Test Owner: [TODO] AXXXXXXXX. Review before merging.';

if (!testCode.startsWith('//')) {
  testCode = `${authorLine}\n${testCode}`;
} else {
  const firstLineEnd = testCode.indexOf('\n');
  const firstLine = firstLineEnd === -1 ? testCode : testCode.slice(0, firstLineEnd);
  if (!firstLine.includes('A0259256U')) {
    testCode = `${authorLine}\n` + (firstLineEnd === -1 ? '' : testCode.slice(firstLineEnd + 1));
  }
}

// Step 4: Normalise line endings and trailing whitespace
testCode = testCode.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
testCode = testCode.split('\n').map(l => l.trimEnd()).join('\n');
testCode = testCode.replace(/\n+$/, '') + '\n';

// Step 5: Derive output filename
const baseName = buildData.file.split('/').pop().replace(/\.js$/, '');
const filename = buildData.testOutputPath || `tests/integration/${baseName}.ai-generated.test.js`;

return [{ json: {
  formattedTestFile: testCode,
  filename,
  sourceFile: buildData.file,
  owner: buildData.owner,
  repo: buildData.repo,
  branch: buildData.branch,
  linesOfCode: testCode.split('\n').length,
  generatedAt: new Date().toISOString(),
} }];

const input = $input.first().json;
const runs = input.workflow_runs || [];

// filter only completed runs
const completed = runs.filter(r => r.status === "completed");

if (completed.length === 0) {
  throw new Error("No completed workflow runs found");
}

// sort latest first
completed.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());

const latest = completed[0];

return [
  {
    json: {
      owner: $('Set Repository Config1').first().json.owner,
      repo: $('Set Repository Config1').first().json.repo,
      run_id: latest.id,
    },
  },
];

const input = $input.first().json;
const artifacts = input.artifacts || [];

//Debug
console.log('Artifacts:', artifacts);

const coverage = artifacts.find(a => a.name === "coverage-summary");

if (!coverage) {
  throw new Error('Artifact "coverage-summary" not found');
}

return [
  {
    json: {
      download_url: coverage.archive_download_url,
    },
  },
];

const input = $input.first().json;
const data = input.data || {};

const result = {
  missing_tests: [],
  low_coverage: [],
  all_files: [],
};

for (const [file, stats] of Object.entries(data)) {
  if (file === 'total') continue;
  if (!stats || typeof stats !== 'object') continue;

  const lines = Number(stats.lines?.pct ?? 0);
  const functions = Number(stats.functions?.pct ?? 0);
  const statements = Number(stats.statements?.pct ?? 0);
  const branches = Number(stats.branches?.pct ?? 0);

  if (!stats.lines || !stats.functions || !stats.statements || !stats.branches) {
    continue;
  }

  const avg = (lines + functions + statements + branches) / 4;
  result.all_files.push({ file, avgCoverage: avg });

  if (avg === 0) {
    result.missing_tests.push(file);
  } else if (avg < 100) {
    result.low_coverage.push({
      file,
      avgCoverage: avg,
    });
  }
}

return [{ json: result }];

const input = $input.first().json;

const low_coverage = input.low_coverage || [];
const missing_tests = input.missing_tests || [];

const COVERAGE_THRESHOLD = 85;

// Rule 1: Remove low coverage gain tests
const passing_coverage = low_coverage.filter(f => f.avgCoverage >= COVERAGE_THRESHOLD);
const removed_low_coverage = low_coverage.filter(f => f.avgCoverage < COVERAGE_THRESHOLD);

// Rule 2: Remove duplicates by file path
const seen = new Set();
const deduped = passing_coverage.filter(f => {
  if (seen.has(f.file)) return false;
  seen.add(f.file);
  return true;
});

// Rule 3: Reject missing tests (0% coverage files)
const rejected_missing = missing_tests;

return [{
  json: {
    valid_files: deduped,
    removed_low_coverage,
    rejected_missing_tests: rejected_missing,
    summary: {
      total_valid: deduped.length,
      total_removed_low_coverage: removed_low_coverage.length,
      total_rejected_missing: rejected_missing.length
    }
  }
}];

const input = $input.first().json;

const old = input.oldCoverage;
const newCov = input.newCoverage;
const improvement = input.improvement;

const message = `*[AI Testing] Coverage Report — CS4218 T05*

Coverage comparison after AI-generated test commit:

Lines:      ${old.lines}% → ${newCov.lines}% (${improvement.lines >= 0 ? '+' : ''}${improvement.lines.toFixed(2)}%)
Statements: ${old.statements}% → ${newCov.statements}% (${improvement.statements >= 0 ? '+' : ''}${improvement.statements.toFixed(2)}%)
Functions:  ${old.functions}% → ${newCov.functions}% (${improvement.functions >= 0 ? '+' : ''}${improvement.functions.toFixed(2)}%)
Branches:   ${old.branches}% → ${newCov.branches}% (${improvement.branches >= 0 ? '+' : ''}${improvement.branches.toFixed(2)}%)

${improvement.lines > 0 || improvement.statements > 0 || improvement.functions > 0 || improvement.branches > 0 ? '✅ Coverage improved. The AI-generated test PR is ready for team review.' : '⚠️ No coverage improvement detected. Manual review of the AI-generated tests is recommended before merging.'}`;

return [{ json: { message } }];

const newData = $input.first().json.newCoverageData;
const oldData = $("Read Coverage JSON1").first().json.data;

const oldTotal = oldData.total || {};
const newTotal = newData.total || {};

const oldLines = oldTotal.lines?.pct || 0;
const newLines = newTotal.lines?.pct || 0;
const oldStatements = oldTotal.statements?.pct || 0;
const newStatements = newTotal.statements?.pct || 0;
const oldFunctions = oldTotal.functions?.pct || 0;
const newFunctions = newTotal.functions?.pct || 0;
const oldBranches = oldTotal.branches?.pct || 0;
const newBranches = newTotal.branches?.pct || 0;

return [{
  json: {
    oldCoverage: {
      lines: oldLines,
      statements: oldStatements,
      functions: oldFunctions,
      branches: oldBranches
    },
    newCoverage: {
      lines: newLines,
      statements: newStatements,
      functions: newFunctions,
      branches: newBranches
    },
    improvement: {
      lines: newLines - oldLines,
      statements: newStatements - oldStatements,
      functions: newFunctions - oldFunctions,
      branches: newBranches - oldBranches
    }
  }
}];

const input = $input.first().json;
const runs = input.workflow_runs || [];
if (runs.length === 0) {
  throw new Error("No coverage workflow runs found for this branch");
}
runs.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
const latest = runs[0];
return [{
  json: {
    owner: $("Commit Test File to Separate Branch").item.json.owner,
    repo: $("Commit Test File to Separate Branch").item.json.repo,
    run_id: latest.id,
  },
}];

const input = $input.first().json;
const artifacts = input.artifacts || [];
const coverage = artifacts.find(a => a.name === "coverage-summary");
if (!coverage) {
  throw new Error('Artifact "coverage-summary" not found');
}
return [{
  json: {
    download_url: coverage.archive_download_url,
  },
}];

const jobsData = $input.first().json;
const jobs = jobsData.jobs || [];

const failedTests = [];
const testFilePath = $("Commit Test File to Separate Branch").item.json.filename;

for (const job of jobs) {
  if (job.conclusion === "failure" || job.conclusion === "cancelled") {
    const steps = job.steps || [];
    for (const step of steps) {
      if (step.name && step.name.toLowerCase().includes("test") && step.conclusion === "failure") {
        failedTests.push({
          jobId: job.id,
          stepName: step.name,
          conclusion: step.conclusion
        });
      }
    }
  }
}

return [{
  json: {
    hasFailures: failedTests.length > 0,
    failedTests,
    testFilePath,
    owner: $("Commit Test File to Separate Branch").item.json.owner,
    repo: $("Commit Test File to Separate Branch").item.json.repo,
    branch: $("Commit Test File to Separate Branch").item.json.branch
  }
}];

// Build Anti-Pattern Prompt — assembles GPT-4o prompt to detect test quality issues.
// Triggered in parallel after PR creation.
// Reads generated test file from Format Test File (P3) and PR number from input.

const prData = $input.first().json;
const formatData = $('Format Test File (P3)').item.json;

const testCode = formatData.formattedTestFile || '';
const sourceFile = formatData.sourceFile || 'unknown';
const owner = formatData.owner || 'cs4218';
const repo = formatData.repo || 'cs4218-2520-ecom-project-cs4218-2520-team5';
const prNumber = prData.number || null;

if (!testCode) {
  throw new Error('No test code found from Format Test File (P3).');
}
if (!prNumber) {
  throw new Error('No PR number in Create New Pull Request response.');
}

const systemPrompt = `You are a senior QA engineer performing automated code review on Jest test files for a MERN stack e-commerce application (Node.js, Express, Mongoose, MongoDB).

Analyze the provided test file and identify anti-patterns across these categories:
1. MISSING_ASSERTIONS: test/it blocks with no expect() calls
2. OVERUSE_OF_MOCKS: mocking the module/layer under test itself (not external deps like Braintree/MongoDB)
3. HARDCODED_VALUES: magic literals/strings that should be parameterized or use BVA variables
4. NO_EDGE_CASES: functions tested only for happy path, missing null, empty string, boundary, or error scenarios
5. BRITTLE_SELECTORS: assertions tied to exact error message strings or status text that may change
6. MISSING_CLEANUP: tests that mutate shared DB/global state without afterEach/afterAll cleanup
7. DUPLICATE_SETUP: repeated beforeEach-style setup code inline in multiple tests instead of shared beforeEach

Return ONLY valid JSON matching this exact schema (no markdown outside the JSON object):
{
  "score": <integer 0-100, 100 = no issues detected>,
  "issues": [
    {
      "type": "<anti-pattern type from list above>",
      "severity": "<critical|warning|info>",
      "description": "<specific description of the issue in the actual code>",
      "lineHint": "<describe() or test() name, or approximate location>",
      "suggestion": "<concrete actionable fix>"
    }
  ],
  "strengths": ["<what this test file does well>"],
  "summary": "<one-paragraph overall assessment of test quality>"
}`;

const userPrompt = `Analyze this Jest test file for ${sourceFile}:

\`\`\`javascript
${testCode.slice(0, 8000)}
\`\`\``;

return [{ json: { systemPrompt, userPrompt, sourceFile, owner, repo, prNumber } }];

// Format Anti-Pattern Report — parses GPT-4o JSON response and builds a
// structured GitHub PR comment with score, issues table, and strengths.

const response = $input.first().json;
const buildData = $('Build Anti-Pattern Prompt').item.json;

const rawText = response.choices?.[0]?.message?.content || '';
if (!rawText) throw new Error('GPT-4o returned empty anti-pattern analysis.');

let analysis;
try { analysis = JSON.parse(rawText); } catch {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) { try { analysis = JSON.parse(m[0]); } catch { analysis = null; } }
}

if (!analysis) {
  analysis = { score: 0, issues: [{ type: 'PARSE_ERROR', severity: 'warning', description: 'Could not parse GPT-4o response.', lineHint: 'N/A', suggestion: 'Review raw response.' }], strengths: [], summary: rawText.slice(0, 500) };
}

const score = typeof analysis.score === 'number' ? analysis.score : 0;
const issues = Array.isArray(analysis.issues) ? analysis.issues : [];
const strengths = Array.isArray(analysis.strengths) ? analysis.strengths : [];
const criticalCount = issues.filter(i => i.severity === 'critical').length;
const warningCount = issues.filter(i => i.severity === 'warning').length;
const infoCount = issues.filter(i => i.severity === 'info').length;
const scoreEmoji = score >= 80 ? '🟢' : score >= 60 ? '🟡' : '🔴';

const issueRows = issues.length === 0
  ? '_No anti-patterns detected. ✅_'
  : issues.map(i => {
      const sev = i.severity === 'critical' ? '🔴 Critical' : i.severity === 'warning' ? '🟡 Warning' : 'ℹ️ Info';
      return `**${sev} — \`${i.type}\`**\n> ${i.description}\n> 📍 _${i.lineHint}_\n> 🔧 ${i.suggestion}`;
    }).join('\n\n');

const strengthRows = strengths.length > 0 ? strengths.map(s => `- ${s}`).join('\n') : '_None specifically noted._';

const comment = `## 🤖 AI Anti-Pattern Detection Report\n\n| | |\n|---|---|\n| **File** | \`${buildData.sourceFile}\` |\n| **Quality Score** | ${scoreEmoji} **${score}/100** |\n| **Issues** | 🔴 ${criticalCount} critical  🟡 ${warningCount} warnings  ℹ️ ${infoCount} info |\n\n---\n\n### Issues Found\n\n${issueRows}\n\n---\n\n### Strengths\n\n${strengthRows}\n\n---\n\n### Overall Assessment\n\n${analysis.summary || ''}\n\n---\n<sub>🤖 Generated by n8n AI Testing Workflow — CS4218 T05</sub>`;

return [{ json: {
  comment,
  telegramMessage: `*[AI Testing] Anti-Pattern Analysis — CS4218 T05*\n\nFile: \`${buildData.sourceFile}\`\nQuality Score: ${scoreEmoji} *${score}/100*\nIssues: 🔴 ${criticalCount} critical | 🟡 ${warningCount} warnings | ℹ️ ${infoCount} info\n\n${criticalCount > 0 ? '⚠️ Action required: ' + criticalCount + ' critical issue(s) identified. Please review and resolve before merging.' : '✅ No critical issues detected. Review warnings at your discretion.'}\n\nFull report posted to the GitHub PR comment.`,
  score, criticalCount, warningCount,
  owner: buildData.owner, repo: buildData.repo, prNumber: buildData.prNumber, sourceFile: buildData.sourceFile,
} }];

// Build Root Cause Prompt — assembles GPT-4o prompt for failure root cause analysis.
// Triggered in parallel on the true branch of Check for Failures.
// Uses: failed step list from Identify Failed Tests + test code from Format Test File (P3).

const failureData = $input.first().json;
const formatData = $('Format Test File (P3)').item.json;

const testCode = formatData.formattedTestFile || '';
const testFilePath = failureData.testFilePath || 'unknown';
const failedSteps = failureData.failedTests || [];
const owner = failureData.owner || 'cs4218';
const repo = failureData.repo || 'cs4218-2520-ecom-project-cs4218-2520-team5';
const branch = failureData.branch || 'main';

if (failedSteps.length === 0) throw new Error('No failed steps found in Identify Failed Tests output.');

const systemPrompt = `You are a senior software engineer performing automated root cause analysis on failed CI/CD test runs for a MERN stack e-commerce application (Node.js, Express, Mongoose, MongoDB, Jest).

You will receive:
1. A list of failed CI job step objects with stepName and conclusion
2. The generated Jest test file that caused the failure

Classify the root cause as exactly one of:
- IMPLEMENTATION_BUG: production source code has a bug that causes the test assertion to fail legitimately
- TEST_BUG: the AI-generated test has incorrect assertions, wrong expected values, or flawed setup/teardown
- ENVIRONMENT_ISSUE: a missing environment variable, wrong configuration, or unavailable dependency
- FLAKY_TEST: non-deterministic behavior such as race conditions, timing dependencies, or unordered results
- IMPORT_ERROR: missing import, incorrect module path, ESM vs CJS mismatch, or undefined export

Return ONLY valid JSON matching this exact schema (no markdown outside the JSON):
{
  "rootCause": "<ROOT_CAUSE type>",
  "confidence": "<high|medium|low>",
  "explanation": "<detailed explanation referencing specific code constructs or step names>",
  "affectedTests": ["<describe block or test() name>"],
  "suggestedFix": "<numbered actionable steps to fix the issue>",
  "isFlaky": <true|false>,
  "flakyIndicators": ["<if isFlaky: specific code patterns indicating flakiness, else empty array>"]
}`;

const userPrompt = `Test file path: ${testFilePath}\n\nFailed CI steps:\n${JSON.stringify(failedSteps, null, 2)}\n\nGenerated test file:\n\`\`\`javascript\n${testCode.slice(0, 6000)}\n\`\`\`\n\nReturn JSON only.`;

return [{ json: { systemPrompt, userPrompt, testFilePath, owner, repo, branch } }];

// Format Root Cause Report — parses GPT-4o JSON response and builds a structured
// GitHub PR comment with failure classification, explanation, and fix steps.

const response = $input.first().json;
const buildData = $('Build Root Cause Prompt').item.json;

const rawText = response.choices?.[0]?.message?.content || '';
if (!rawText) throw new Error('GPT-4o returned empty root cause analysis.');

let analysis;
try { analysis = JSON.parse(rawText); } catch {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) { try { analysis = JSON.parse(m[0]); } catch { analysis = null; } }
}

if (!analysis) {
  analysis = { rootCause: 'UNKNOWN', confidence: 'low', explanation: rawText.slice(0, 500), affectedTests: [], suggestedFix: 'Review CI logs manually.', isFlaky: false, flakyIndicators: [] };
}

const causeEmoji = { IMPLEMENTATION_BUG: '🐛', TEST_BUG: '🧪', ENVIRONMENT_ISSUE: '⚙️', FLAKY_TEST: '🎲', IMPORT_ERROR: '📦', UNKNOWN: '❓' }[analysis.rootCause] || '❓';
const confidenceEmoji = analysis.confidence === 'high' ? '🟢' : analysis.confidence === 'medium' ? '🟡' : '🔴';

const affectedList = (analysis.affectedTests || []).map(t => `- \`${t}\``).join('
') || '- _Could not determine_';
const flakySection = analysis.isFlaky ? `

### ⚠️ Flaky Test Indicators

${(analysis.flakyIndicators || []).map(f => `- ${f}`).join('
')}` : '';

const comment = `## 🤖 AI Root Cause Analysis

| | |
|---|---|
| **File** | \`${buildData.testFilePath}\` |
| **Root Cause** | ${causeEmoji} **${analysis.rootCause}** |
| **Confidence** | ${confidenceEmoji} ${analysis.confidence} |

---

### Explanation

${analysis.explanation}

### Affected Tests

${affectedList}

### Suggested Fix

${analysis.suggestedFix}${flakySection}

---
<sub>🤖 Generated by n8n AI Testing Workflow — CS4218 T05</sub>`;

const prNumber = (() => { try { return $('Create New Pull Request').item.json.number; } catch { return null; } })();

return [{ json: {
  comment,
  telegramMessage: `*[AI Testing] Failure Root Cause Analysis — CS4218 T05*

File: \`${buildData.testFilePath}\`
Classification: ${causeEmoji} *${analysis.rootCause}* (${analysis.confidence} confidence)

${analysis.explanation.slice(0, 200)}

⚠️ CI tests have failed. Please review the suggested fix in the PR comment and resolve before re-running the pipeline.`,
  rootCause: analysis.rootCause, prNumber,
  owner: buildData.owner, repo: buildData.repo,
} }];

// Build Mutation Suggestions Prompt — assembles GPT-4o prompt to identify code mutations
// that reveal weaknesses in the passing test suite.
// Triggered in parallel from Log Test Success.
// Uses Build Prompt (P3) for source code and Format Test File (P3) for test code.

const buildData = $('Build Prompt (P3)').item.json;
const formatData = $('Format Test File (P3)').item.json;

const sourceCode = buildData.sourceCode || '';
const sourceFile = buildData.file || 'unknown';
const testCode = formatData.formattedTestFile || '';
const owner = formatData.owner || 'cs4218';
const repo = formatData.repo || 'cs4218-2520-ecom-project-cs4218-2520-team5';

if (!sourceCode) throw new Error('No source code in Build Prompt (P3) — sourceCode is empty.');
if (!testCode) throw new Error('No test code in Format Test File (P3) — formattedTestFile is empty.');

const prNumber = (() => { try { return $('Create New Pull Request').item.json.number; } catch { return null; } })();

const systemPrompt = `You are a mutation testing expert analyzing a Jest test suite for a Node.js/Express/Mongoose e-commerce application.

Mutation testing applies small targeted source code changes (mutations) to check if the test suite catches them (kills the mutant). A survived mutant indicates a gap in test coverage.

For each mutation you identify:
1. Specify the exact original code snippet and mutated version (max 100 chars each)
2. Describe the semantic behavior change
3. Classify as: killed (tests would fail), survived (tests still pass), or uncertain
4. If survived: suggest a specific new test case to kill it

Mutation types to use:
- BOUNDARY: change comparison operator (e.g. > to >=, < to <=, === to !==)
- ARITHMETIC: change arithmetic operator (+ to -, * to /)
- LOGICAL: change logical operator (&& to ||, || to &&)
- NULL_RETURN: return null instead of computed value
- CONDITION_FLIP: negate a boolean condition or guard clause
- OFF_BY_ONE: add or subtract 1 from a numeric count, index, or limit constant
- REMOVE_CALL: remove a function call or middleware invocation

Return ONLY valid JSON matching this exact schema:
{
  "mutationScore": <integer 0-100, estimated % of listed mutations the tests would kill>,
