  if (m.suggestedTest) parts.push(`💡 **Add this test to kill the mutant:**\n> ${m.suggestedTest}`);
  return parts.join('\n');
}).join('\n\n---\n\n');

const comment = `## 🧬 AI Mutation Testing Suggestions\n\n| | |\n|---|---|\n| **File** | \`${buildData.sourceFile}\` |\n| **Estimated Mutation Score** | ${scoreEmoji} **${score}%** |\n| **Mutations Analysed** | ${analysis.totalMutations || 0} total (✅ ${analysis.killedCount || 0} killed, ❌ ${analysis.survivedCount || 0} survived) |\n\n---\n\n${mutationBlocks || '_No mutations analysed._'}\n\n---\n\n### 📋 Recommendation\n\n${analysis.recommendation}\n\n---\n<sub>🤖 Generated by n8n AI Testing Workflow — CS4218 T05</sub>`;

