const data = $input.first().json;

// --- Part 1: Summary Header ---
const statusEmoji = data.overallStatus === 'PASSED' ? '✅' : '❌';
const scoreNum = parseFloat(data.overallHealthScore);
const scoreEmoji = scoreNum > 80 ? '🟢' : scoreNum > 60 ? '🟡' : '🔴';

const part1 = [
  `🧪 *AI Test Report*`,
  ``,
  `${statusEmoji} *Status:* ${data.overallStatus}`,
  `${scoreEmoji} *Health Score:* ${data.overallHealthScore}/100`,
  `🔖 *Pipeline:* \`${data.pipelineId}\``,
  `🕐 *Timestamp:* ${data.timestamp}`,
  ``,
  `━━━━━━━━━━━━━━━━━━━━━━`,
  `📊 *Test Results*`,
  `━━━━━━━━━━━━━━━━━━━━━━`,
  `• Unit Tests: ✅ ${data.unitTests?.passed || 0} passed / ❌ ${data.unitTests?.failed || 0} failed / 📦 ${data.unitTests?.totalTests || 0} total`,
  `• Integration: ${data.integrationTests?.status || 'N/A'}`,
  `• UI Tests:    ${data.uiTests?.status || 'N/A'}`,
  `• NFR Tests:   ${data.nfrTests?.status || 'N/A'}`,
  ``,
  `━━━━━━━━━━━━━━━━━━━━━━`,
  `🤖 *AI Analysis Summary*`,
  `━━━━━━━━━━━━━━━━━━━━━━`,
  `• Anti-patterns detected: ${data.aiAnalysis?.antiPatterns?.length || 0}`,
  `• Auto-fixable issues:    ${data.autoFixes?.highConfidenceFixes || 0}`,
  `• Total auto-fixes:       ${data.autoFixes?.totalFixes || 0}`,
  `• New test suggestions:   ${data.aiAnalysis?.generatedTests?.length || 0}`,
].join('\n');

// --- Part 2: AI Full Report (truncated to fit Telegram 4096 limit) ---
const fullReport = data.reportContent || 'No report content available.';
const maxReportLength = 3800;
const truncatedReport = fullReport.length > maxReportLength
  ? fullReport.substring(0, maxReportLength) + '\n\n_...report truncated. See HTML report for full details._'
  : fullReport;

const part2 = [
  ``,
  `━━━━━━━━━━━━━━━━━━━━━━`,
  `📄 *Full AI Report*`,
  `━━━━━━━━━━━━━━━━━━━━━━`,
  truncatedReport
].join('\n');

// --- Part 3: Auto-Fix Details ---
const fixes = data.autoFixes?.fixes || [];
const fixLines = fixes.slice(0, 5).map((fix, i) =>
  `${i + 1}. \`${fix.file}\` — ${fix.fixType} (${(fix.confidence * 100).toFixed(0)}% confidence)\n   _${fix.explanation}_`
);

const part3 = [
  ``,
  `━━━━━━━━━━━━━━━━━━━━━━`,
  `🔧 *Auto-Fix Details*`,
  `━━━━━━━━━━━━━━━━━━━━━━`,
  fixLines.length > 0 ? fixLines.join('\n') : '_No auto-fixes generated._',
  fixes.length > 5 ? `_...and ${fixes.length - 5} more fixes. See HTML report._` : ''
].join('\n');

return [{
  json: {
    ...data,
    telegramMessages: {
      summary: part1,
      fullReport: part2,
      autoFix: part3
    }
  }
}];

// Take high-confidence auto-fixes and prepare for commit
const fixes = $input.first().json.fixes || [];
const highConfidenceFixes = fixes.filter(f => f.confidence >= 0.85);

if (highConfidenceFixes.length === 0) {
  return [{ json: { action: 'skip', reason: 'No high-confidence fixes available' } }];
}

// Prepare commit data
const commitFiles = highConfidenceFixes.map(fix => ({
  path: fix.file,
  content: fix.fixedCode,
  message: `fix(test): ${fix.fixType} - ${fix.explanation}`,
  fixType: fix.fixType
}));

const commitMessage = `🤖 AI Auto-fix: ${highConfidenceFixes.length} test improvements\n\n` +
  highConfidenceFixes.map(f => `- ${f.fixType}: ${f.explanation}`).join('\n') +
  `\n\nGenerated by n8n AI Testing Agent`;

// Extract repository info from previous nodes or use default
const previousData = $('Aggregate All Test Results').first()?.json || {};
const repository = previousData.repository || 'owner/repo'; // Fallback

return [{
  json: {
    action: 'commit',
    repository: repository,
    owner: repository.split('/')[0],
    repo: repository.split('/')[1],
    baseBranch: 'main',
    newBranch: `ai-test-fix-${Date.now()}`,
    commitMessage,
    files: commitFiles,
    totalFixes: highConfidenceFixes.length
  }
}];

// Extract SHA from base branch and prepare for new branch creation
const response = $input.first().json;
const baseSha = response.object?.sha || response.sha;

const previousData = $('Should Auto-Commit?').first().json;

return [{
  json: {
    ...previousData,
    baseSha: baseSha
  }
}];

// Prepare file update operations
const data = $input.first().json;
const previousData = $('Extract SHA').first().json;

// Get files to commit
const files = previousData.files || [];

// Return each file as a separate item for batch processing
return files.map(file => ({
  json: {
    owner: previousData.owner,
    repo: previousData.repo,
    branch: previousData.newBranch,
    filePath: file.path,
    fileContent: Buffer.from(file.content).toString('base64'),
    commitMessage: file.message,
    totalFiles: files.length
  }
}));

// Wait for all commits to complete and prepare PR creation
const items = $input.all();

if (items.length === 0) {
  return [{ json: { error: 'No files committed' } }];
}

// Get data from first item (all have same repo/branch info)
const firstItem = items[0].json;
const previousData = $('Extract SHA').first().json;

return [{
  json: {
    owner: firstItem.owner,
    repo: firstItem.repo,
    newBranch: firstItem.branch,
    baseBranch: previousData.baseBranch || 'main',
    totalFixes: previousData.totalFixes,
    commitMessage: previousData.commitMessage,
    filesCommitted: items.length
  }
}];

// Parse PR creation response and prepare notification
const prResponse = $input.first().json;

const prUrl = prResponse.html_url || '';
const prNumber = prResponse.number || 0;

return [{
