  '━━━━━━━━━━━━━━━━━━━━━━',
  '🔍 *Quality Analysis*',
  '━━━━━━━━━━━━━━━━━━━━━━',
  `• Quality Score: ${data.qualityScore}/100`,
  `• Quality Gate: ❌ ${data.qualityGate}`,
  `• Total Issues: ${data.issueCount}`,
  `• Critical Issues: ${data.criticalIssues}`,
  '',
  '⚠️ *Critical Issues Found:*',
  ...issueLines,
  '',
  '_Tests NOT committed — fix issues and retry_'
].join('\n');

return [{ json: { message, data } }];

// Extract and prepare input for NFR test generation
const payload = $input.first().json;

const repository = payload.repository || 'owner/repo';
const branch = payload.branch || 'main';
const apiEndpoints = payload.apiEndpoints || [];
const baseUrl = payload.baseUrl || 'http://localhost:3000';
const existingNfrCode = payload.existingNfrCode || '';

return [{
  json: {
    repository,
    branch,
    owner: repository.split('/')[0],
    repo: repository.split('/')[1],
    apiEndpoints,
    baseUrl,
    existingNfrCode,
    timestamp: new Date().toISOString()
  }
}];

// Parse OpenAI response and extract NFR scripts
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let parsed = {};
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  parsed = { rawContent: content, parseError: e.message };
}

// Validate each script
function validateScript(script, type) {
  if (!script) return { valid: false, reason: 'Missing script' };
  const hasOptions = script.includes('export const options');
  const hasDefault = script.includes('export default function');
  const hasChecks = script.includes('check(');
  const hasThresholds = script.includes('thresholds');
  return {
    valid: hasOptions && hasDefault,
    hasChecks,
    hasThresholds,
    lineCount: script.split('\n').length
  };
}

const scripts = {
  loadTest: parsed.loadTest || {},
  stressTest: parsed.stressTest || {},
  spikeTest: parsed.spikeTest || {},
  soakTest: parsed.soakTest || {}
};

const validations = {
  loadTest: validateScript(scripts.loadTest?.script, 'load'),
  stressTest: validateScript(scripts.stressTest?.script, 'stress'),
  spikeTest: validateScript(scripts.spikeTest?.script, 'spike'),
  soakTest: validateScript(scripts.soakTest?.script, 'soak')
};

const previousData = $('Prepare NFR Input').first().json;

return [{
  json: {
    ...previousData,
    scripts,
    validations,
    summary: parsed.summary || {},
    allValid: Object.values(validations).every(v => v.valid),
    tokensUsed: response.usage?.total_tokens || 0,
    parseError: parsed.parseError || null
  }
}];

// Parse NFR quality check response
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let qualityReport = {};
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  qualityReport = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  qualityReport = { issues: [], qualityScore: 0, parseError: e.message };
}

const previousData = $('Parse NFR Scripts').first().json;

return [{
  json: {
    ...previousData,
    qualityReport,
    qualityScore: qualityReport.qualityScore || 0,
    qualityGate: qualityReport.qualityGate || 'FAILED',
    issueCount: qualityReport.issues?.length || 0,
    criticalIssues: qualityReport.issues?.filter(i => i.severity === 'CRITICAL').length || 0
  }
}];

// Prepare all 4 NFR scripts for GitHub commit
const data = $input.first().json;
const scripts = data.scripts || {};

const filesToCommit = [
  {
    path: scripts.loadTest?.filePath || 'src/test/nfr/k6_load_test.js',
    content: Buffer.from(scripts.loadTest?.script || '').toString('base64'),
    commitMessage: 'test(nfr): AI-generated k6 load test script'
  },
  {
    path: scripts.stressTest?.filePath || 'src/test/nfr/k6_stress_test.js',
    content: Buffer.from(scripts.stressTest?.script || '').toString('base64'),
    commitMessage: 'test(nfr): AI-generated k6 stress test script'
  },
  {
    path: scripts.spikeTest?.filePath || 'src/test/nfr/k6_spike_test.js',
    content: Buffer.from(scripts.spikeTest?.script || '').toString('base64'),
    commitMessage: 'test(nfr): AI-generated k6 spike test script'
  },
  {
    path: scripts.soakTest?.filePath || 'src/test/nfr/k6_soak_test.js',
    content: Buffer.from(scripts.soakTest?.script || '').toString('base64'),
    commitMessage: 'test(nfr): AI-generated k6 soak test script'
  }
].filter(f => f.content.length > 0);

return [{
  json: {
    ...data,
    filesToCommit,
    totalFilesToCommit: filesToCommit.length
  }
}];

// Split NFR files for individual commits
const branchData = $input.first().json;
const sha = branchData.object?.sha || branchData.sha;

const commitData = $('Prepare NFR Commit Files').first().json;
const files = commitData.filesToCommit || [];

return files.map(file => ({
  json: {
    owner: commitData.owner,
    repo: commitData.repo,
    branch: commitData.branch,
    filePath: file.path,
    fileContent: file.content,
    commitMessage: file.commitMessage,
    sha
  }
}));

// Build Telegram failure notification for NFR
const data = $input.first().json;
const issues = data.qualityReport?.issues || [];
const criticalIssues = issues.filter(i => i.severity === 'CRITICAL');

const issueLines = criticalIssues.slice(0, 5).map((issue, i) =>
  `${i + 1}. [${issue.script}] *${issue.pattern}* — ${issue.description}`
);

const message = [
  '❌ *NFR Scripts — Quality Gate FAILED*',
  '',
  `📦 *Repository:* ${data.repository}`,
  `🌿 *Branch:* ${data.branch}`,
  '',
  '━━━━━━━━━━━━━━━━━━━━━━',
  '🔍 *Quality Analysis*',
  '━━━━━━━━━━━━━━━━━━━━━━',
  `• Quality Score: ${data.qualityScore}/100`,
  `• Quality Gate: ❌ ${data.qualityGate}`,
  `• Total Issues: ${data.issueCount}`,
  `• Critical Issues: ${data.criticalIssues}`,
  '',
  '⚠️ *Critical Issues:*',
  ...issueLines,
  '',
  '_Scripts NOT committed — fix issues and retry_'
].join('\n');

return [{ json: { message } }];
